class OidcAuthenticationFilter extends OncePerRequestFilter {
    private final OidcService oidcService;

    OidcAuthenticationFilter(OidcService oidcService) {
        this.oidcService = oidcService;
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain) throws ServletException, IOException {
        String path = request.getRequestURI();

        if ("/login".equals(path)) {
            response.sendRedirect(oidcService.buildAuthorizationUrl(request));
            return;
        }

        if ("/oidc/callback".equals(path)) {
            handleCallback(request, response);
            return;
        }

        Authentication current = SecurityContextHolder.getContext().getAuthentication();
        if (current == null && request.getSession(false) != null) {
            Object sessionUser = request.getSession(false).getAttribute("OIDC_USER");
            if (sessionUser instanceof OidcUserSession session) {
                Authentication auth = new UsernamePasswordAuthenticationToken(session, "N/A", session.authorities().stream().map(org.springframework.security.core.authority.SimpleGrantedAuthority::new).collect(Collectors.toSet()));
                SecurityContextHolder.getContext().setAuthentication(auth);
            }
        }

        filterChain.doFilter(request, response);
    }

    private void handleCallback(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String code = request.getParameter("code");
        String state = request.getParameter("state");
        String savedState = (String) request.getSession(true).getAttribute("OIDC_STATE");
        String savedNonce = (String) request.getSession(true).getAttribute("OIDC_NONCE");

        if (!StringUtils.hasText(code) || !StringUtils.hasText(state) || !Objects.equals(state, savedState)) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid authorization response");
            return;
        }

        OidcTokenResponse tokenResponse = oidcService.exchangeCodeForTokens(code);
        OidcUserSession userSession = oidcService.createUserSessionFromIdTokenAndUserInfo(tokenResponse.idToken(), tokenResponse.accessToken());

        Map<String, Object> idClaims = userSession.idTokenClaims();
        String tokenNonce = String.valueOf(idClaims.get("nonce"));
        if (StringUtils.hasText(savedNonce) && !Objects.equals(savedNonce, tokenNonce)) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Invalid nonce");
            return;
        }

        request.getSession(true).setAttribute("OIDC_USER", userSession);
        request.getSession(true).removeAttribute("OIDC_STATE");
        request.getSession(true).removeAttribute("OIDC_NONCE");

        Authentication auth = new UsernamePasswordAuthenticationToken(
                userSession,
                "N/A",
                userSession.authorities().stream().map(org.springframework.security.core.authority.SimpleGrantedAuthority::new).collect(Collectors.toSet())
        );
        SecurityContextHolder.getContext().setAuthentication(auth);

        response.sendRedirect("/");
    }
}

